---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

import type { ToggleVariantProps } from "@/components/ui/toggle"

type ToggleGroupValue = string | string[]

type Props = HTMLAttributes<"div"> &
  ToggleVariantProps & {
    defaultValue?: ToggleGroupValue
    multiple?: boolean
    orientation?: "horizontal" | "vertical"
    loop?: boolean
    disabled?: boolean
    spacing?: number
  }

const {
  class: className,
  defaultValue,
  multiple = false,
  orientation = "horizontal",
  loop = true,
  disabled = false,
  spacing = 0,
  variant = "default",
  size = "default",
  style,
  ...props
} = Astro.props

const serializedDefaultValue = Array.isArray(defaultValue)
  ? defaultValue.join(" ")
  : defaultValue
const mergedStyle = `--gap:${spacing}px;${style ?? ""}`
---

<div
  data-slot="toggle-group"
  data-default-value={serializedDefaultValue}
  data-multiple={multiple}
  data-orientation={orientation}
  data-horizontal={orientation === "horizontal" ? true : undefined}
  data-vertical={orientation === "vertical" ? true : undefined}
  data-loop={loop}
  data-disabled={disabled}
  data-variant={variant}
  data-size={size}
  data-spacing={spacing}
  style={mergedStyle}
  class={cn(
    "group/toggle-group flex w-fit flex-row items-center gap-[--gap] rounded-md data-[spacing=0]:data-[variant=outline]:shadow-xs data-[orientation=vertical]:flex-col data-[orientation=vertical]:items-stretch",
    className
  )}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/toggle-group"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

import { toggleVariants, type ToggleVariantProps } from "@/components/ui/toggle"

type Props = HTMLAttributes<"button"> &
  ToggleVariantProps & {
    value: string
    disabled?: boolean
  }

const {
  class: className,
  value,
  disabled,
  variant,
  size,
  type = "button",
  ...props
} = Astro.props
---

<button
  data-slot="toggle-group-item"
  data-value={value}
  data-disabled={disabled}
  data-variant={variant}
  data-size={size}
  type={type}
  class={cn(
    toggleVariants({
      variant: variant ?? undefined,
      size: size ?? undefined,
    }),
    "shrink-0 group-data-[spacing=0]/toggle-group:rounded-none group-data-[spacing=0]/toggle-group:px-2 group-data-[spacing=0]/toggle-group:shadow-none focus:z-10 focus-visible:z-10 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-end]:pr-1.5 group-data-[spacing=0]/toggle-group:has-data-[icon=inline-start]:pl-1.5 group-data-horizontal/toggle-group:first:rounded-l-md group-data-vertical/toggle-group:first:rounded-t-md group-data-horizontal/toggle-group:last:rounded-r-md group-data-vertical/toggle-group:last:rounded-b-md data-[state=on]:bg-muted group-data-[variant=outline]/toggle-group:border group-data-[variant=outline]/toggle-group:border-input group-data-[variant=outline]/toggle-group:bg-transparent group-data-[variant=outline]/toggle-group:shadow-xs group-data-[variant=outline]/toggle-group:hover:bg-muted",
    className
  )}
  {...props}
>
  <slot />
</button>
